import '../models/sync_conflict.dart';import '../models/sync_plan.dart';import 'sync_conflict_detector.dart';class SyncPlanService{SyncPlan buildPlan({required Map<String,String> localHashes,required Map<String,String> remoteHashes}){final conflicts=SyncConflictDetector().compare(localHashes:localHashes,remoteHashes:remoteHashes);return SyncPlan(createdAtIso:DateTime.now().toIso8601String(),conflicts:conflicts,uploads:conflicts.where((c)=>c.type==SyncConflictType.localOnly).map((c)=>c.path).toList(),downloads:conflicts.where((c)=>c.type==SyncConflictType.remoteOnly).map((c)=>c.path).toList());}}
